sql:
SELECT c.country_name, hi.year, hi.max_infection_rate
FROM health_indicators hi
JOIN countries c ON hi.country_id = c.country_id;

SELECT country_id, country_name
FROM countries
WHERE population > (SELECT AVG(population) FROM countries);

external_knowledge:
- "sailed in an ocean of wealth" refers to the income share of the top 10% being greater than 0.6; 
- "sea of longevity" refers to an average healthy life expectancy above 75 years;
- "golden milestone of 75 years" is a metaphor for reaching a significant healthy life expectancy;
- "vast are their shores in terms of population" means the population size of the countries;
- "maritime giants" is a metaphor for countries that meet the wealth and longevity criteria.

sql:
SELECT country_id, SQRT(AVG(max_infection_rate)) AS sqrt_average_max_infection_rate
FROM health_indicators
GROUP BY country_id;

SELECT countries.country_name, health_indicators.max_infection_rate
FROM countries
JOIN health_indicators ON countries.country_id = health_indicators.country_id;

SELECT freedom_to_make_life_choices
FROM quality_of_life_indicators
WHERE country_id = 1;
